import heapq

def heuristic(a, b):
    return abs(a[0] - b[0]) + abs(a[1] - b[1])

def reconstruct_path(came_from, current):
    path = []
    while current in came_from:
        path.append(current)
        current = came_from[current]
    path.append(current)
    return path[::-1]

def astar(grid, start, end):
    rows, cols = len(grid), len(grid[0])

    if not (0 <= start[0] < rows and 0 <= start[1] < cols and
            0 <= end[0] < rows and 0 <= end[1] < cols):
        return None

    if grid[start[0]][start[1]] == 1 or grid[end[0]][end[1]] == 1:
        return None

    open_set = []
    heapq.heappush(open_set, (0, start))

    came_from = {}

    g_score = {start: 0}
    f_score = {start: heuristic(start, end)}

    closed_set = set()

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    while open_set:
        current_f, current_pos = heapq.heappop(open_set)

        if current_pos == end:
            return reconstruct_path(came_from, current_pos)

        if current_pos in closed_set:
            continue

        closed_set.add(current_pos)

        for dx, dy in directions:
            neighbor_pos = (current_pos[0] + dx, current_pos[1] + dy)

            if not (0 <= neighbor_pos[0] < rows and 0 <= neighbor_pos[1] < cols):
                continue

            if grid[neighbor_pos[0]][neighbor_pos[1]] == 1:
                continue

            tentative_g_score = g_score.get(current_pos, float('inf')) + 1

            if tentative_g_score < g_score.get(neighbor_pos, float('inf')):
                came_from[neighbor_pos] = current_pos
                g_score[neighbor_pos] = tentative_g_score
                f_score[neighbor_pos] = tentative_g_score + heuristic(neighbor_pos, end)
                heapq.heappush(open_set, (f_score[neighbor_pos], neighbor_pos))

    return None
